#include<bits/stdc++.h>
using namespace std;
int fa[300010],n,m;
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
int lst,cnt=0;
struct node
{
    int x,y;
}e[300010];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&e[i].x,&e[i].y);
        if(find(e[i].x)==find(e[i].y))
        {
            printf("No");
            return 0;
        }
        merge(e[i].x,e[i].y);
    }
    printf("Yes\n");
    for(int i=1;i<m;i++)
    {
        printf("%d %d\n",e[i].x,e[i].y);
    }
    int lst=e[m].x;
    for(int i=1;i<=n;i++)
    {
        if(find(i)==i&&find(i)!=find(e[m].x))
        {
            printf("%d %d\n",lst,i);
            lst=i;
        }
    }
    printf("%d %d",e[m].y,lst);
    return 0;
}
